diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..e505475f7c30 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3130,6 +3130,34 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 1, TrueSI->getTrueValue());
         return &SI;
       }
+      // select(select(C0, true, C1), select(C0, Y, Z), X) -> select(C0, Y, select(C1, Z, X))
+      // This is the logical OR pattern: outer condition is (C0 || C1), true value is select(C0, Y, Z), false value is X.
+      if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+        if (CondSI->getType()->isIntOrIntVectorTy(1) &&
+            match(CondSI->getTrueValue(), m_One())) {
+          Value *C0 = CondSI->getCondition();
+          Value *C1 = CondSI->getFalseValue();
+          Value *Y = TrueSI->getTrueValue();
+          Value *Z = TrueSI->getFalseValue();
+          bool CondMatch = false;
+          if (TrueSI->getCondition() == C0) {
+            CondMatch = true;
+          } else if (match(TrueSI->getCondition(), m_Not(m_Specific(C0)))) {
+            CondMatch = true;
+            std::swap(Y, Z);
+          }
+          if (CondMatch) {
+            // Replace condition with C0
+            replaceOperand(SI, 0, C0);
+            // Keep true value as Y
+            replaceOperand(SI, 1, Y);
+            // Create inner false select: select(C1, Z, X)
+            Value *InnerSelect = Builder.CreateSelect(C1, Z, FalseVal);
+            replaceOperand(SI, 2, InnerSelect);
+            return &SI;
+          }
+        }
+      }
     }
   }
   if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
@@ -3148,6 +3176,58 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         return &SI;
       }
     }
+    // select(select(C0, C1, false), X, select(C0, Y, Z)) -> select(C0, select(C1, X, Y), Z)
+    if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+      if (CondSI->getType()->isIntOrIntVectorTy(1) &&
+          match(CondSI->getFalseValue(), m_Zero())) {
+        Value *C0 = CondSI->getCondition();
+        Value *C1 = CondSI->getTrueValue();
+        Value *Y = FalseSI->getTrueValue();
+        Value *Z = FalseSI->getFalseValue();
+        bool CondMatch = false;
+        if (FalseSI->getCondition() == C0) {
+          CondMatch = true;
+        } else if (match(C0, m_Not(m_Specific(FalseSI->getCondition())))) {
+          CondMatch = true;
+          std::swap(Y, Z);
+        }
+        if (CondMatch) {
+          // Replace condition with C0
+          replaceOperand(SI, 0, C0);
+          // Create inner select: select(C1, X, Y)
+          Value *InnerSelect = Builder.CreateSelect(C1, TrueVal, Y);
+          replaceOperand(SI, 1, InnerSelect);
+          // Replace false value with Z
+          replaceOperand(SI, 2, Z);
+          return &SI;
+        }
+      }
+      // select(select(C0, true, C1), select(C0, Y, Z), X) -> select(C0, Y, select(C1, Z, X))
+      // This is the logical OR pattern: outer condition is (C0 || C1), true value is select(C0, Y, Z), false value is X.
+      if (match(CondSI->getTrueValue(), m_One())) {
+        Value *C0 = CondSI->getCondition();
+        Value *C1 = CondSI->getFalseValue();
+        Value *Y = FalseSI->getTrueValue();
+        Value *Z = FalseSI->getFalseValue();
+        bool CondMatch = false;
+        if (FalseSI->getCondition() == C0) {
+          CondMatch = true;
+        } else if (match(C0, m_Not(m_Specific(FalseSI->getCondition())))) {
+          CondMatch = true;
+          std::swap(Y, Z);
+        }
+        if (CondMatch) {
+          // Replace condition with C0
+          replaceOperand(SI, 0, C0);
+          // Keep true value as Y
+          replaceOperand(SI, 1, Y);
+          // Create inner false select: select(C1, Z, X)
+          Value *InnerSelect = Builder.CreateSelect(C1, Z, TrueVal);
+          replaceOperand(SI, 2, InnerSelect);
+          return &SI;
+        }
+      }
+    }
   }

